<?php $heading='Find a Doctor';$subheading='Search by doctor name, qualification or specialty.';require __DIR__.'/_hero.php';?><section class="section"><form class="filter-bar" method="get"><input name="q" value="<?=e($q)?>" placeholder="Doctor, specialty or qualification"><select name="department"><option value="0">All departments</option><?php foreach($departments as$d):?><option value="<?=$d['id']?>" <?=$selectedDepartment==(int)$d['id']?'selected':''?>><?=e($d['name'])?></option><?php endforeach;?></select><button class="btn">Search</button></form><div class="doctor-grid listing"><?php foreach($doctors as$d):?><article class="doctor-card"><div class="doctor-photo">⚕</div><div><span class="status">Available: <?=e($d['available_days'])?></span><h3><?=e($d['name'])?></h3><p><?=e($d['designation'])?></p><b><?=e($d['specialization'])?></b><small><?=e($d['qualifications'])?> • <?=e($d['experience_years'])?> years</small><a class="btn small" href="<?=url('doctor?id='.$d['id'])?>">View Profile</a></div></article><?php endforeach;?></div><?php if(!$doctors):?><div class="empty">No doctors matched your search.</div><?php endif;?></section>

